const raw = JSON.parse($input.first().json.body);

const evalTypes = raw.evalTypes || {};
const areas = raw.areas || {};
const alerts = raw.alerts || [];

const evalActivas = Object.entries(evalTypes)
  .filter(([,v]) => v)
  .map(([k]) => ({ express:'Exprés', completa:'Completa', subcontratacion:'Subcontratación', reforzada:'Reforzada', internacional:'Internacional' }[k]))
  .join(', ');

const areasList = ['solicitante','abastecimiento','cumplimiento','finanzas','legal','subcontratacion'];
const labels = { solicitante:'Solicitante', abastecimiento:'Abastecimiento', cumplimiento:'Cumplimiento', finanzas:'Finanzas', legal:'Legal', subcontratacion:'Subcontratación' };
const icons = { aprobado:'✅', rechazado:'❌', observacion:'✏️' };

const resumenSlack = areasList.map(a => {
  const d = areas[a]?.decision;
  const icon = icons[d] || '⏳';
  const note = areas[a]?.notes ? ` — _"${areas[a].notes.substring(0, 60)}${areas[a].notes.length > 60 ? '…' : ''}"_` : '';
  const extras = areas[a]?.extraDocs?.length ? ` (+${areas[a].extraDocs.length} doc adicional)` : '';
  return `• ${icon} *${labels[a]}*: ${d || 'Pendiente'}${note}${extras}`;
}).join('\n');

const sevIcon = { leve:'🔵', media:'🟡', grave:'🔴' };
const alertasActivas = alerts.filter(a => a.activa);
const alertasSlack = alertasActivas.map(a => `• ${sevIcon[a.severidad] || ''} *${a.alerta}* (${a.severidad})${a.comentario ? ` — _${a.comentario}_` : ''}`).join('\n') || '_Sin alertas activas_';
const alertasResumen = alerts.map(a => `${a.alerta} [${a.activa ? a.severidad : 'off'}]${a.comentario ? ` (${a.comentario})` : ''}`).join(' | ');

return [{ json: {
  client:    raw.client,
  email:     raw.email,
  timestamp: raw.timestamp,
  eval_activas: evalActivas || 'Ninguna',

  eval_express:         evalTypes.express         ?? false,
  eval_completa:        evalTypes.completa        ?? false,
  eval_subcontratacion: evalTypes.subcontratacion ?? false,
  eval_reforzada:       evalTypes.reforzada       ?? false,
  eval_internacional:   evalTypes.internacional   ?? false,

  dec_solicitante:     areas.solicitante?.decision     ?? null,
  notes_solicitante:   areas.solicitante?.notes        ?? '',
  extras_solicitante:  (areas.solicitante?.extraDocs   || []).join(', '),

  dec_abastecimiento:  areas.abastecimiento?.decision  ?? null,
  notes_abastecimiento:areas.abastecimiento?.notes     ?? '',
  extras_abastecimiento:(areas.abastecimiento?.extraDocs|| []).join(', '),

  dec_cumplimiento:    areas.cumplimiento?.decision    ?? null,
  notes_cumplimiento:  areas.cumplimiento?.notes       ?? '',
  extras_cumplimiento: (areas.cumplimiento?.extraDocs  || []).join(', '),

  dec_finanzas:        areas.finanzas?.decision        ?? null,
  notes_finanzas:      areas.finanzas?.notes           ?? '',
  extras_finanzas:     (areas.finanzas?.extraDocs      || []).join(', '),

  dec_legal:           areas.legal?.decision           ?? null,
  notes_legal:         areas.legal?.notes              ?? '',
  extras_legal:        (areas.legal?.extraDocs         || []).join(', '),

  dec_subcontratacion: areas.subcontratacion?.decision ?? null,
  notes_subcontratacion:areas.subcontratacion?.notes  ?? '',
  extras_subcontratacion:(areas.subcontratacion?.extraDocs|| []).join(', '),

  alerts_active: raw.alertsActive ?? alertasActivas.length,
  alerts_resumen: alertasResumen,
  _resumen_slack: resumenSlack,
  _alertas_slack: alertasSlack,
}}];

